+unsafe fn dot_neon_f64(a: &[f64], b: &[f64]) -> f64 {
+    use std::arch::aarch64::*;
+
+    let n = a.len().min(b.len());
+    let chunks = n / 4;
+    let remainder = n % 4;
+
+    let mut acc0 = vdupq_n_f64(0.0);
+    let mut acc1 = vdupq_n_f64(0.0);
