+    println!("  Spectral Fiedler (A|B): {:.4} | {:.4}", fa, fb);
+    println!("================================================================");
+
+    let sig = z < -2.0;
+    let diff = j_best < 0.80;
+    if sig && diff {
+        println!("\n  CONCLUSION: Spectral bisection discovers a population boundary");
