+        z0 = p*z0 + gauss(rng); z1 = p*z1 + gauss(rng); z2 = phi*z2 + gauss(rng);
+        data.push([
+            (hr_b + z0*0.8).max(40.0),
+            (hrv_b + coup*z0*1.5 + z1*0.4).max(5.0),
+            (st_b + z2*500.0 + cross*z0*150.0).max(500.0),
