+
+fn intra_corr(c: &[[f64; N_SENS]; N_SENS], m: usize) -> f64 {
+    let ss: Vec<usize> = (0..N_SENS).filter(|&s| member(s) == m).collect();
+    let mut sum = 0.0; let mut n = 0;
+    for i in 0..ss.len() { for j in (i+1)..ss.len() { sum += c[ss[i]][ss[j]]; n += 1; } }
