+    for f in feats { for d in 0..N_PAIRS { mu[d] += f[d]; } }
+    for d in 0..N_PAIRS { mu[d] /= n; }
+    for f in feats { for d in 0..N_PAIRS { sd[d] += (f[d] - mu[d]).powi(2); } }
