+fn pearson(a: &[f64], b: &[f64], ma: f64, mb: f64) -> f64 {
+    let (mut c, mut va, mut vb) = (0.0, 0.0, 0.0);
+    for i in 0..a.len() {
+        let (da, db) = (a[i] - ma, b[i] - mb);
+        c += da * db; va += da * da; vb += db * db;
+    }
+    let d = (va * vb).sqrt();
+    if d < 1e-12 { 0.0 } else { c / d }
