+            row[i] = (bl[i] + season + ns[i] * gauss(rng)).max(0.0);
+        }
+        row
+    }).collect()
+}
+
+fn null_dist(rng: &mut StdRng) -> Vec<Vec<f64>> {
+    let mut out = vec![Vec::with_capacity(NULL_PERMS); 4];
+    for _ in 0..NULL_PERMS {
+        let d = gen_null(rng);
