+}
+
+fn fiedler_seg(edges: &[(u64,u64,f64)], s: usize, e: usize) -> f64 {
+    let n=e-s; if n<3 { return 0.0; }
+    let se: Vec<(usize,usize,f64)> = edges.iter().filter(|(u,v,_)| {
