+// ── Constants ───────────────────────────────────────────────────────────
+const NCH: usize = 16;
+const SR: usize = 256;
+const WIN_S: usize = 10;
+const SEED: u64 = 42_0911;
+const NPAIRS: usize = NCH * (NCH - 1) / 2;
+const NFEAT: usize = NPAIRS + NCH * 4; // 120 corr + 48 band + 16 dom_freq
