+fn zscore(obs: f64, null: &[f64]) -> f64 {
+    let n = null.len() as f64;
+    let mu: f64 = null.iter().sum::<f64>() / n;
+    let sd = (null.iter().map(|v| (v - mu).powi(2)).sum::<f64>() / n).sqrt();
+    if sd < 1e-12 { 0.0 } else { (obs - mu) / sd }
+}
