+    println!("  Found: {} RFI lines (easy, strong)", rfi_ok.len());
+
+    let (s1t, s1_hit, s1_exp) = region_excess(&sg, S1_F0, S1_F1, S1_T0, S1_T1);
+    let (s2t, s2_hit, s2_exp) = region_excess(&sg, S2_F0, S2_F1, S2_T0, S2_T1);
