+    }).map(|(u, v, w)| (*u as usize - start, *v as usize - start, *w)).collect();
+    if se.is_empty() { return 0.0; }
+    estimate_fiedler(&CsrMatrixView::build_laplacian(n, &se), 100, 1e-8).0
+}
