+        let mut f = [0.0_f64; NF];
+        for v in 0..NR {
+            let vals: Vec<f64> = s.iter().map(|d| d[v]).collect();
+            let b = v * NS;
+            f[b] = mean(&vals); f[b+1] = std_dev(&vals); f[b+2] = acf1(&vals);
+            f[b+3] = trend(&vals); f[b+4] = vrange(&vals);
+        }
